def end():
    print("程序结束")
    exit()

def inp():
    try:
        return float(input())
    except:
        print("数值错误")
        end()

n = int(input())
sum = 0
if n == 0:
    print("除0错误，n不能等0")
    end()

for _ in range(n):
    sum += inp()

print("正确")
print(f"avg={sum/n:.2f}")
end()
